import logging
import json
import os
import sys
from datetime import datetime

from flask import Flask, request, jsonify, g

app = Flask(__name__)

# --- Logging Configuration ---
# Create a logger instance
logger = logging.getLogger(__name__)
logger.setLevel(logging.INFO) # Set to INFO for general logging, DEBUG for more verbose

# Define a log file path
LOG_DIR = 'logs'
if not os.path.exists(LOG_DIR):
    os.makedirs(LOG_DIR)
LOG_FILE = os.path.join(LOG_DIR, 'app.log')

# Create a formatter
# This formatter includes more detail like timestamp, level, module, function, line number
# and process/thread IDs.
formatter = logging.Formatter(
    '[%(asctime)s] [%(levelname)s] [%(process)d:%(thread)d] '
    '[%(name)s:%(funcName)s:%(lineno)d] - %(message)s'
)

# File Handler - for detailed logs, rotates logs after 10MB, keeps 5 backup files
file_handler = logging.handlers.RotatingFileHandler(
    LOG_FILE, maxBytes=10*1024*1024, backupCount=5
)
file_handler.setFormatter(formatter)
logger.addHandler(file_handler)

# Console Handler - for immediate feedback during development
console_handler = logging.StreamHandler(sys.stdout)
console_handler.setFormatter(formatter)
logger.addHandler(console_handler)

# Set Flask's default logger to use our configured logger
# This makes sure Flask's internal logs (like request access logs) also go through our setup
app.logger.handlers = logger.handlers
app.logger.setLevel(logger.level) # Make Flask's logger use the same level

# --- Utility Functions for Logging Sensitive Data ---
# List of header keys whose values should be redacted in logs
SENSITIVE_HEADERS = ['Authorization', 'Cookie', 'X-API-Key']
# List of body field keys whose values should be redacted in logs
SENSITIVE_FIELDS = ['password', 'passwd', 'token', 'access_token', 'refresh_token', 'secret', 'api_key', 'private_key']

def redact_dict(data_dict, sensitive_fields=SENSITIVE_FIELDS):
    """Recursively redact sensitive fields from a dictionary."""
    if not isinstance(data_dict, dict):
        return data_dict

    redacted_data = {}
    for key, value in data_dict.items():
        if key.lower() in sensitive_fields:
            redacted_data[key] = '[REDACTED]'
        elif isinstance(value, dict):
            redacted_data[key] = redact_dict(value, sensitive_fields)
        elif isinstance(value, list):
            redacted_data[key] = [redact_dict(item, sensitive_fields) if isinstance(item, (dict, list)) else item for item in value]
        else:
            redacted_data[key] = value
    return redacted_data

def redact_headers(headers, sensitive_headers=SENSITIVE_HEADERS):
    """Redact sensitive headers."""
    redacted_headers = {}
    for key, value in headers.items():
        if key.lower() in [h.lower() for h in sensitive_headers]:
            redacted_headers[key] = '[REDACTED]'
        else:
            redacted_headers[key] = value
    return redacted_headers

# --- Flask Hooks for Request/Response Logging ---

@app.before_request
def log_request_info():
    # Generate a unique ID for each request for easier tracing
    request_id = datetime.now().strftime('%Y%m%d%H%M%S%f')
    g.request_id = request_id # Store in Flask's global context for access during response/error logging
    g.start_time = datetime.now() # Store start time to calculate request duration

    # User information placeholder
    # In a real application, you would extract this from an authenticated session/token
    user_info = {'user_id': 'anonymous', 'ip_address': request.remote_addr}

    log_data = {
        'request_id': request_id,
        'event': 'API_REQUEST',
        'method': request.method,
        'path': request.path,
        'full_path': request.full_path,
        'referrer': request.referrer,
        'user_agent': request.user_agent.string,
        'headers': redact_headers(dict(request.headers)),
        'user_info': user_info
    }

    # Log request body if present and not a file upload
    if request.data:
        try:
            # Try to parse as JSON
            json_data = request.get_json(silent=True)
            if json_data is not None:
                log_data['body'] = redact_dict(json_data)
            else:
                # Fallback for form data or plain text
                log_data['body'] = request.data.decode('utf-8')
        except Exception as e:
            logger.warning(f"Failed to parse request body for logging (Request ID: {request_id}): {e}")
            log_data['body'] = '[RAW BODY PARSE ERROR]'

    logger.info(f"Incoming Request: {json.dumps(log_data)}")

@app.after_request
def log_response_info(response):
    request_id = g.get('request_id', 'N/A')
    elapsed_time_ms = (datetime.now() - g.start_time).total_seconds() * 1000 if hasattr(g, 'start_time') else 'N/A'

    log_data = {
        'request_id': request_id,
        'event': 'API_RESPONSE',
        'status_code': response.status_code,
        'response_headers': redact_headers(dict(response.headers)),
        'elapsed_time_ms': f"{elapsed_time_ms:.2f}ms" if isinstance(elapsed_time_ms, (int, float)) else elapsed_time_ms
    }

    # Log response body for certain content types or if it's an error response
    # Be cautious with logging large response bodies or sensitive information
    if response.content_type and 'application/json' in response.content_type and response.is_json:
        try:
            # We need to load from response.data directly as response.get_json() might consume the stream
            response_json = json.loads(response.data)
            log_data['response_body'] = redact_dict(response_json)
        except Exception:
            log_data['response_body'] = '[JSON PARSE ERROR]'
    elif response.status_code >= 400: # Log body for error responses regardless of content type
        try:
            log_data['response_body'] = response.data.decode('utf-8')
        except Exception:
            log_data['response_body'] = '[RAW BODY DECODE ERROR]'

    logger.info(f"Outgoing Response: {json.dumps(log_data)}")
    return response

@app.errorhandler(Exception)
def log_and_handle_exception(e):
    # This captures unhandled exceptions
    request_id = g.get('request_id', 'N/A')
    logger.exception(
        f"Unhandled exception during request (Request ID: {request_id}). "
        f"Method: {request.method}, Path: {request.path}"
    )
    # Return a generic error response to the client
    response = jsonify({"error": "An internal server error occurred.", "request_id": request_id})
    response.status_code = 500
    return response

