@app.route('/login', methods=['POST'])
def login():
    data = request.get_json(silent=True)
    if not data:
        logger.warning(f"Login attempt with no JSON data (Request ID: {g.request_id})")
        return jsonify({"message": "Invalid request body"}), 400

    username = data.get('username')
    password = data.get('password') # This password will be redacted in logs by log_request_info

    # Simulate authentication logic
    if username == 'user' and password == 'pass':
        logger.info(f"Successful login for user: {username} (Request ID: {g.request_id})")
        return jsonify({"message": "Login successful", "token": "fake_jwt_token_123"})
    else:
        logger.warning(f"Failed login attempt for user: {username} (Request ID: {g.request_id})")
        # Do not log the actual provided password here either
        return jsonify({"message": "Invalid credentials"}), 401

@app.route('/data', methods=['GET', 'POST'])
def data_endpoint():
    if request.method == 'GET':
        logger.info(f"Fetching data (Request ID: {g.request_id}).")
        return jsonify({"message": "Here is your data", "items": ["item1", "item2"]})
    elif request.method == 'POST':
        data = request.get_json(silent=True)
        if not data:
            logger.warning(f"POST to /data with no JSON data (Request ID: {g.request_id})")
            return jsonify({"message": "Invalid request body"}), 400

        logger.info(f"Received data: {data.get('payload', 'no payload')} (Request ID: {g.request_id})")
        # Example of sensitive data that might be passed (and will be redacted)
        if 'private_info' in data:
            logger.info("Private info detected in POST data, should be redacted in logs.")
        return jsonify({"message": "Data received", "status": "success", "received_data": data})

